// SectionReading, ReadingAnalysis, and ScoreTier are defined in the Simon block below

const PHASE_SECTION_IDS = [
  'phase-introductie',
  'phase-instructie',
  'phase-verwerking',
  'phase-afronding',
] as const

const PHASE_SECTION_LABELS: Record<string, string> = {
  'phase-introductie': 'Introductie',
  'phase-instructie':  'Instructie',
  'phase-verwerking':  'Verwerking',
  'phase-afronding':   'Afronding',
}

// Phase key → OutlinePhase name (used to split EXPERIMENT_TEXT)
const PHASE_ID_TO_OUTLINE: Record<string, string> = {
  'phase-introductie': 'introductie',
  'phase-instructie':  'instructie',
  'phase-verwerking':  'verwerking',
  'phase-afronding':   'afronding',
}

// ─── Reading tier — three levels ────────────────────────────────────────────
type ReadingTier = 'Slordig' | 'Oppervlakkig' | 'Duidelijk'

// ─── Edit tier — binary: either enough edits or not ─────────────────────────
type EditTier = 'AIGegenereerd' | 'Menselijk'

// Colour for the reading tier label in the verdict sentence
const READ_TIER_COLOUR: Record<ReadingTier, string> = {
  Slordig: 'text-red-600',
  Oppervlakkig:  'text-amber-500',
  // Duidelijk + Menselijk → green; Duidelijk + AIGegenereerd → amber (see SimonPanel)
  Duidelijk:   'text-emerald-600',
}

// ─── Per-phase minimum reading times ─────────────────────────────────────────
// minMs      = hard gate: below this the block stays Slordig.
// DuidelijkMs = time at which the block reaches full (80 pt) time score.
const PHASE_READ_CONFIG: Record<string, { minMs: number; DuidelijkMs: number }> = {
  'phase-introductie': { minMs:  50_000, DuidelijkMs: 100_000 },
  'phase-instructie':  { minMs: 30_000, DuidelijkMs: 50_000 },
  'phase-verwerking':  { minMs:  5_000, DuidelijkMs: 15_000 },
  'phase-afronding':   { minMs:  25_000, DuidelijkMs: 45_000 },
}
const MOUSE_SATURATE = 150

function readScoreFromMetrics(
  m: { totalTimeMs: number; maxScrollDepth: number; mouseMovements: number; visits: number } | undefined,
  sectionId: string
): number {
  if (!m) return 0
  const cfg = PHASE_READ_CONFIG[sectionId] ?? { minMs: 8_000, DuidelijkMs: 30_000 }
  if (m.totalTimeMs < cfg.minMs) return 0
  const timeScore   = Math.min(80, Math.round((m.totalTimeMs / cfg.DuidelijkMs) * 80))
  const scrollScore = Math.min(12, Math.round(m.maxScrollDepth * 12))
  const mouseScore  = Math.min(8,  Math.round((m.mouseMovements / MOUSE_SATURATE) * 8))
  return Math.min(100, timeScore + scrollScore + mouseScore)
}

function readTierFromScore(score: number): ReadingTier {
  if (score >= 80) return 'Duidelijk'
  if (score >= 60) return 'Oppervlakkig'
  return 'Slordig'
}

// ─── Per-phase edit score — binary ───────────────────────────────────────────
// Below EDIT_MENSELIJK_RATIO of characters changed → AIGegenereerd.
// At or above → Menselijk. No middle tier.
const EDIT_MENSELIJK_RATIO = 0.1   // ≥ 10 % of original chars changed → Menselijk

// Split EXPERIMENT_TEXT into per-phase buckets once at module load.
const ORIGINAL_PHASE_TEXT: Record<string, string> = (() => {
  const buckets: Record<string, string[]> = {
    introductie: [], instructie: [], verwerking: [], afronding: [],
  }
  let current: string | null = null
  for (const line of EXPERIMENT_TEXT.split('\n')) {
    const m = line.match(/^##\s+(.+)$/)
    if (m) {
      const key = m[1].trim().toLowerCase()
      if (key in buckets) { current = key; continue }
    }
    if (current) buckets[current].push(line)
  }
  const result: Record<string, string> = {}
  for (const [k, lines] of Object.entries(buckets)) {
    result[k] = lines.join('\n').trim()
  }
  return result
})()

function simpleLevenshtein(a: string, b: string): number {
  const m = a.length, n = b.length
  if (m === 0) return n
  if (n === 0) return m
  let prev = Array.from({ length: n + 1 }, (_, j) => j)
  let curr = new Array(n + 1).fill(0)
  for (let i = 1; i <= m; i++) {
    curr[0] = i
    for (let j = 1; j <= n; j++) {
      curr[j] = a[i - 1] === b[j - 1]
        ? prev[j - 1]
        : 1 + Math.min(prev[j], curr[j - 1], prev[j - 1])
    }
    ;[prev, curr] = [curr, prev]
  }
  return prev[n]
}

function editTierForPhase(currentPhaseText: string, phaseKey: string): EditTier {
  const original = ORIGINAL_PHASE_TEXT[PHASE_ID_TO_OUTLINE[phaseKey] ?? ''] ?? ''
  if (!original) return 'AIGegenereerd'
  const dist  = simpleLevenshtein(
    currentPhaseText.replace(/\s+/g, ' ').trim(),
    original.replace(/\s+/g, ' ').trim()
  )
  const ratio = dist / Math.max(1, original.length)
  return ratio >= EDIT_MENSELIJK_RATIO ? 'Menselijk' : 'AIGegenereerd'
}

// ─── Analysis types ───────────────────────────────────────────────────────────
interface SectionReading {
  sectionId:  string
  label:      string
  readScore:  number
  readTier:   ReadingTier
  editTier:   EditTier
}

interface ReadingAnalysis {
  sections:          SectionReading[]
  averageReadScore:  number
  overallReadTier:   ReadingTier
  overallEditTier:   EditTier        // Menselijk only if ALL phases are Menselijk
  // Two lowest-scoring read blocks (distinct labels)
  weakestReadLabels: string[]
  // Two lowest-scoring edit blocks by Levenshtein ratio (distinct labels)
  weakestEditLabels: string[]
}

function buildReadingAnalysis(
  sectionMetrics: Record<string, { totalTimeMs: number; maxScrollDepth: number; mouseMovements: number; visits: number }>,
  phaseBlocks: Record<string, string[]>,
  manualEditTexts?: Record<string, string | null>
): ReadingAnalysis {
  const sections: SectionReading[] = PHASE_SECTION_IDS.map((id) => {
    const readScore = readScoreFromMetrics(sectionMetrics[id], id)
    const readTier  = readTierFromScore(readScore)
    const outlineKey = PHASE_ID_TO_OUTLINE[id] ?? ''
    // Student condition: use manual edit text if available; badge condition: use phaseBlocks
    const currentText = manualEditTexts
      ? (manualEditTexts[outlineKey] !== null && manualEditTexts[outlineKey] !== undefined
          ? stripHtmlForEdit(manualEditTexts[outlineKey] as string)
          : (phaseBlocks[outlineKey] ?? []).join('\n'))
      : (phaseBlocks[outlineKey] ?? []).join('\n')
    const editTier  = editTierForPhase(currentText, id)
    return { sectionId: id, label: PHASE_SECTION_LABELS[id], readScore, readTier, editTier }
  })

  const averageReadScore = Math.round(
    sections.reduce((s, r) => s + r.readScore, 0) / sections.length
  )
  const overallReadTier = readTierFromScore(averageReadScore)

  // Overall edit is Menselijk only when ALL phases have been edited enough
  const overallEditTier: EditTier = sections.every(s => s.editTier === 'Menselijk')
    ? 'Menselijk'
    : 'AIGegenereerd'

  // Two weakest read blocks — only phases that have NOT yet reached Duidelijk.
  // This means a hint only disappears when the phase genuinely reaches the top
  // tier, not just because another phase temporarily scores slightly higher.
  const weakestReadLabels = [...sections]
    .filter(s => s.readTier !== 'Duidelijk')
    .sort((a, b) => a.readScore - b.readScore)
    .slice(0, 2)
    .map(s => s.label)

  // Two weakest edit blocks — approximate by checking which phases are still AIGegenereerd first,
  // then fall back to all phases sorted by how close they are to the threshold.
  // Since editTier is binary, we define "weakest" as: AIGegenereerd phases come first.
  const weakestEditLabels = [...sections]
    .sort((a, b) => {
      // AIGegenereerd < Menselijk
      if (a.editTier !== b.editTier) return a.editTier === 'AIGegenereerd' ? -1 : 1
      // Within same tier, fall back to readScore for stability
      return a.readScore - b.readScore
    })
    .slice(0, 2)
    .map(s => s.label)

  return { sections, averageReadScore, overallReadTier, overallEditTier, weakestReadLabels, weakestEditLabels }
}

// Mounts the IntersectionObserver tracker + polls every 500ms.
function SimonTracker({ onAnalysis, phaseBlocks, manualEditTexts }: {
  onAnalysis: (a: ReadingAnalysis) => void
  phaseBlocks: Record<string, string[]>
  manualEditTexts?: Record<string, string | null>
}) {
  const { getSnapshot } = useReadingTracker([...PHASE_SECTION_IDS])
  const callbackRef     = useRef(onAnalysis)
  callbackRef.current   = onAnalysis
  const blocksRef       = useRef(phaseBlocks)
  blocksRef.current     = phaseBlocks
  const manualRef       = useRef(manualEditTexts)
  manualRef.current     = manualEditTexts

  useEffect(() => {
    const id = setInterval(() => {
      const snap = getSnapshot()
      callbackRef.current(
        buildReadingAnalysis(
          snap.sections as Record<string, { totalTimeMs: number; maxScrollDepth: number; mouseMovements: number; visits: number }>,
          blocksRef.current,
          manualRef.current
        )
      )
    }, 500)
    return () => clearInterval(id)
  }, [getSnapshot])

  return null
}

// ─── SimonPanel ───────────────────────────────────────────────────────────────
// Verdict logic:
//   Reading tier (Slordig / Oppervlakkig / Duidelijk) drives the label.
//   "en AI gegenereerd" qualifier is appended ONLY when reading = Duidelijk
//   AND edit = AIGegenereerd. When that qualifier is shown, the colour stays
//   amber (not green) and the avatar stays at the Oppervlakkig face.
//
// Hints:
//   • Reading < Duidelijk  → "Voor meer duidelijkheid, verifieer de [block] en de [block]."
//   • Reading = Duidelijk + edit = AIGegenereerd
//                          → "Om de les verder te verbeteren, maak het persoonlijker in de [block] of [block]."
//   • Reading = Duidelijk + edit = Menselijk → no hint
//
// To replace emoji with a custom image, swap the avatar div for:
//   <img
//     src={readTier === 'Duidelijk' && editTier === 'Menselijk' ? '/simon-happy.png'
//       : readTier === 'Oppervlakkig' || (readTier === 'Duidelijk' && editTier === 'AIGegenereerd')
//         ? '/simon-neutral.png' : '/simon-sad.png'}
//     alt="Simon"
//     className="w-14 h-14 flex-shrink-0 rounded-lg object-cover"
//   />
//   Place image files in the /public folder of the project.
function SimonPanel({ analysis }: { analysis: ReadingAnalysis | null }) {
  if (!analysis) {
    return (
      <div className="mb-4 rounded-xl border border-blue-100 bg-blue-50 overflow-hidden">
        <div className="px-4 py-2.5">
          <p className="text-sm font-semibold text-gray-800">Simon de virtuele student</p>
        </div>
        <div className="px-4 pb-3 flex items-start gap-3">
          <img src={IMG_VS_Neutral} alt="Simon" className="w-14 h-14 flex-shrink-0 rounded-lg object-cover" />
          <p className="text-sm text-gray-600 leading-relaxed pt-1">
            Simon kijkt over je schouders mee, lees de tekst op je eigen tempo door.
          </p>
        </div>
      </div>
    )
  }

  const { overallReadTier, overallEditTier, weakestReadLabels, weakestEditLabels } = analysis

  // ── Qualifier text and connector word per (readTier × editTier) ─────────────
  // Slordig + AI  → "en AI gegenereerd"
  // Slordig + Mens → "maar Menselijk"
  // Oppervlakkig  + AI  → "maar AI gegenereerd"
  // Oppervlakkig  + Mens → "en Menselijk"
  // Duidelijk   + AI  → "en AI gegenereerd"  (label stays amber, avatar stays neutral)
  // Duidelijk   + Mens → no qualifier
  type Qualifier = { connector: string; text: string } | null
  const qualifier: Qualifier = (() => {
    if (overallReadTier === 'Slordig') {
      return overallEditTier === 'AIGegenereerd'
        ? { connector: 'en', text: 'AI gegenereerd' }
        : { connector: 'maar', text: 'Menselijk' }
    }
    if (overallReadTier === 'Oppervlakkig') {
      return overallEditTier === 'AIGegenereerd'
        ? { connector: 'maar', text: 'AI gegenereerd' }
        : { connector: 'en', text: 'Menselijk' }
    }
    // Duidelijk
    return overallEditTier === 'AIGegenereerd'
      ? { connector: 'maar', text: 'AI gegenereerd' }
      : null
  })()

  // Colour: Duidelijk+AI stays amber; all other combos use the reading tier colour
  const labelColour = (overallReadTier === 'Duidelijk' && overallEditTier === 'AIGegenereerd')
    ? 'text-amber-500'
    : READ_TIER_COLOUR[overallReadTier]

  // ── Hint ────────────────────────────────────────────────────────────────────
  let hint: React.ReactNode = null
  if (overallReadTier !== 'Duidelijk') {
    // Reading not yet Duidelijk → suggest which blocks to verify
    const [first, second] = weakestReadLabels
    if (first && second && first !== second) {
      hint = <>Voor meer duidelijkheid, lees de <strong>{first}</strong> en de <strong>{second}</strong> (nog eens) door.</>
    } else if (first) {
      hint = <>Voor meer duidelijkheid, lees de <strong>{first}</strong> (nog eens) door.</>
    }
  } else if (overallEditTier === 'AIGegenereerd') {
    // Reading is Duidelijk but edit score is low → personalise hint
    const aiBlocks = weakestEditLabels.filter((_, i, arr) => arr.indexOf(_) === i).slice(0, 2)
    const [first, second] = aiBlocks
    if (first && second && first !== second) {
      hint = <>Om de les verder te verbeteren, maak het persoonlijker in de <strong>{first}</strong> of <strong>{second}</strong>.</>
    } else if (first) {
      hint = <>Om de les verder te verbeteren, maak het persoonlijker in de <strong>{first}</strong>.</>
    }
  }

  return (
    <div className="mb-4 rounded-xl border border-blue-100 bg-blue-50 overflow-hidden">
      <div className="px-4 py-2.5">
        <p className="text-sm font-semibold text-gray-800">Simon de virtuele student</p>
      </div>
      <div className="px-4 pb-3 flex items-start gap-3">
        <img
          src={
            overallReadTier === 'Slordig'
              ? IMG_VS_Unhappy
              : overallReadTier === 'Duidelijk' && overallEditTier === 'Menselijk'
                ? IMG_VS_Happy
                : IMG_VS_Neutral
          }
          alt="Simon"
          className="w-14 h-14 flex-shrink-0 rounded-lg object-cover"
        />
        <div className="flex-1 min-w-0">
          <p className="text-sm text-gray-600 leading-relaxed">
            Simon heeft de tekst gelezen en vindt de tekst{' '}
            <span className={`font-bold ${labelColour}`}>
              {overallReadTier}
              {qualifier && (
                <span className="font-normal"> {qualifier.connector} {qualifier.text}</span>
              )}
            </span>.
          </p>
          {hint && (
            <p className="text-sm text-gray-600 mt-1.5 leading-relaxed">
              {hint}
            </p>
          )}
        </div>
      </div>
    </div>
  )
}

// Empathy variant of ChatPanel for LesTab.
// Simon lives outside the Max card, as a standalone panel below the lesdoel card.
function EmpathyChatPanel({ lesdoel, analysis }: { lesdoel: string; analysis: ReadingAnalysis | null }) {
  return (
    <div className="hidden lg:flex lg:flex-col lg:w-2/5 p-6 bg-white overflow-y-auto gap-4">
      <LesdoelCard lesdoel={lesdoel} />
      <SimonPanel analysis={analysis} />
    </div>
  )
}

// ─── Root ─────────────────────────────────────────────────────────────────────
function ExperimentPage() {

  const [appStep, setAppStep]           = useState<AppStep>('library')
  // Top-level tab: details | authoring (like original Lesdetails / Auteursomgeving)
  const [topTab, setTopTab]             = useState<'details' | 'authoring'>('details')
  // Inner authoring step
  const [activeTab, setActiveTab]       = useState<AuthoringTab>('lesplan')

  // LesDetails
  const [educatieNiveau, setEducatieNiveau]                   = useState('')
  const [educatieSpecifiekNiveau, setEducatieSpecifiekNiveau] = useState('')
  const [educatieSpecifiekeRichting, setEducatieSpecifiekeRichting] = useState('')
  const [customEducation, setCustomEducation]                 = useState('')
  const [customSubLevel, setCustomSubLevel]                   = useState('')
  const [onderwerp, setOnderwerp]                             = useState('')
  const [lesdoel, setLesdoel]                                 = useState('')
  const [showLesdoelInput, setShowLesdoelInput]               = useState(false)
  const [lesdoelLoading, setLesdoelLoading]                   = useState(false)
  const [kwalificatieEnabled, setKwalificatieEnabled]         = useState(false)
  const [educationStandards, setEducationStandards]           = useState<{ id: string; description: string; subject: string; expanded: boolean }[]>([])
  const [taxonomieEnabled, setTaxonomieEnabled]               = useState(false)
  const [selectedTaxonomie, setSelectedTaxonomie]             = useState('')
  const [selectedTaxNiveau, setSelectedTaxNiveau]             = useState('')

  // Lesplan
  const [lesduur, setLesduur]           = useState<number | undefined>()
  const VERWERKING                      = 'Schrijf een werkstuk over het verschil tussen formatieve en summatieve evaluatie.'

  // Lesoverzicht
  const [lesoverzichtLoaded, setLesoverzichtLoaded] = useState(false)
  const [lessonOutline, setLessonOutline] = useState<Record<OutlinePhase, { active: boolean; topics: { id: string; title: string }[] }>>({
    introductie: { active: true, topics: [
      { id: '1', title: 'Inzicht in evaluatievormen' },
      { id: '2', title: 'Verbinding met eerdere kennis' },
      { id: '3', title: 'Introductie lesdoel' },
      { id: '4', title: 'Motivatie voor leren' },
    ]},
    instructie: { active: true, topics: [
      { id: '5', title: 'Verschil tussen formatieve en summatieve evaluaties' },
      { id: '6', title: 'Definitie van formatieve evaluatie' },
      { id: '7', title: 'Definitie van summatieve evaluatie' },
      { id: '8', title: 'Voorbeelden van formatieve evaluatie' },
      { id: '9', title: 'Voorbeelden van summatieve evaluatie' },
    ]},
    verwerking: { active: true, topics: [
      { id: '10', title: 'Werkstuk met beoordelingscriteria' },
      { id: '11', title: 'Opdrachtbeschrijving' },
      { id: '12', title: 'Stappen' },
      { id: '13', title: 'Materialen' },
    ]},
    afronding: { active: true, topics: [
      { id: '14', title: 'Reflectie op evaluaties en leerproces' },
      { id: '15', title: 'Evaluatie van het lesdoel' },
      { id: '16', title: 'Reflectie op eigen werk' },
      { id: '17', title: 'Vooruitblik naar toekomstig leren' },
    ]},
  })

  // Les
  const [lesText, setLesText]     = useState(EXPERIMENT_TEXT)
  const [lesLoaded, setLesLoaded] = useState(false)

  // phaseBlocks lives in the parent so it survives LesTab unmounting on tab navigation
  const [phaseBlocks, setPhaseBlocks] = useState<Record<OutlinePhase, string[]>>(() => {
    const phases: OutlinePhase[] = ['introductie', 'instructie', 'verwerking', 'afronding']
    const phaseNames: Record<OutlinePhase, string> = {
      introductie: 'introductie', instructie: 'instructie',
      verwerking: 'verwerking',   afronding: 'afronding',
    }
    const buckets: Record<OutlinePhase, string[]> = { introductie: [], instructie: [], verwerking: [], afronding: [] }
    const result:  Record<OutlinePhase, string[]> = { introductie: [], instructie: [], verwerking: [], afronding: [] }
    let currentPhase: OutlinePhase | null = null
    for (const line of EXPERIMENT_TEXT.split('\n')) {
      const m = line.match(/^##\s+(.+)$/)
      if (m) {
        const matched = (Object.keys(phaseNames) as OutlinePhase[]).find(k => phaseNames[k] === m[1].trim().toLowerCase())
        if (matched) { currentPhase = matched; continue }
      }
      if (currentPhase) buckets[currentPhase].push(line)
    }
    for (const phase of phases) {
      const content = buckets[phase].join('\n').trim()
      result[phase] = content ? [content] : []
    }
    return result
  })

  // Share modal
  const [shareModalOpen, setShareModalOpen] = useState(false)
  const [shareTab, setShareTab]             = useState<'students' | 'colleagues'>('students')
  const [submitting, setSubmitting]         = useState(false)
  const [submitted, setSubmitted]           = useState(false)
  const [lesNextLoading, setLesNextLoading]   = useState(false)
  const [submitError, setSubmitError]       = useState<string | null>(null)

  const participantIdRef = React.useRef('unknown')
  const conditionRef     = React.useRef('student')
  // Mirror in state so conditional rendering (NudgeBox etc.) re-renders when they change
  const [participantId, setParticipantId] = useState('unknown')
  const [condition, setCondition] = useState('student') 

  // ── New experiment measurements ──────────────────────────────────────────
  const [aiInteractions, setAiInteractions]   = useState<AiInteraction[]>([])
  const [lesEditMs, setLesEditMs]             = useState(0)
  const lesEditMsRef                          = React.useRef(0)   // always-current mirror for async reads
  const lesEditStartRef                       = React.useRef<number | null>(null)
  /** Call when entering the Les tab */
  const handleLesTabEnter = React.useCallback(() => {
    lesEditStartRef.current = Date.now()
  }, [])

/** Call when leaving the Les tab */
  const handleLesTabLeave = React.useCallback(() => {
    if (lesEditStartRef.current !== null) {
      const elapsed = Date.now() - lesEditStartRef.current
      lesEditMsRef.current += elapsed
      setLesEditMs(lesEditMsRef.current)
      lesEditStartRef.current = null
    }
  }, [])

  /** Called by MaxSidebarChat for every completed prompt/response pair */
  const handleAiInteraction = React.useCallback((interaction: Omit<AiInteraction, 'index'>) => {
    setAiInteractions(prev => [...prev, { ...interaction, index: prev.length + 1 }])
  }, [])

  // Latest manual edit count reported by LesTab
  const [manualEditCount, setManualEditCount] = useState(0)
  const manualEditCountRef = React.useRef(0)   // always-current mirror for async reads
  const handleManualEditCount = React.useCallback((count: number) => {
    manualEditCountRef.current = count
    setManualEditCount(count)
  }, [])

  useEffect(() => {
    const p   = new URLSearchParams(window.location.search)
    const pid = p.get('uid') || p.get('pid') || 'unknown'
    const cnd = p.get('cond') || p.get('condition') || 'student'
    // Write to refs first — submit handlers read from here, never stale
    participantIdRef.current = pid
    conditionRef.current     = cnd
    // Also update state so NudgeBox and any conditional rendering reacts
    setParticipantId(pid)
    setCondition(cnd)
  }, [])


  // Reading analysis state — lifted here so it survives tab switches.
  // stableSetAnalysis merges incoming data by keeping the highest read score
  // seen so far per phase, so navigating away (Les → Lesoverzicht → Les)
  // never resets accumulated reading time back to zero.
  const [readingAnalysis, setReadingAnalysis] = useState<ReadingAnalysis | null>(null)
  const readingAnalysisRef = React.useRef<ReadingAnalysis | null>(null)   // always-current mirror for async reads
  const stableSetAnalysis = useCallback((incoming: ReadingAnalysis) => {
    setReadingAnalysis(prev => {
      let result: ReadingAnalysis
      if (!prev) {
        result = incoming
      } else {
        const mergedSections: SectionReading[] = incoming.sections.map(ns => {
          const ps = prev.sections.find(s => s.sectionId === ns.sectionId)
          const readScore = ps ? Math.max(ps.readScore, ns.readScore) : ns.readScore
          return { ...ns, readScore, readTier: readTierFromScore(readScore) }
        })

        const averageReadScore = Math.round(
          mergedSections.reduce((s, r) => s + r.readScore, 0) / mergedSections.length
        )
        const overallReadTier   = readTierFromScore(averageReadScore)
        const overallEditTier: EditTier = mergedSections.every(s => s.editTier === 'Menselijk')
          ? 'Menselijk' : 'AIGegenereerd'
        const weakestReadLabels = [...mergedSections]
          .filter(s => s.readTier !== 'Duidelijk')
          .sort((a, b) => a.readScore - b.readScore).slice(0, 2).map(s => s.label)
        const weakestEditLabels = [...mergedSections]
          .sort((a, b) => {
            if (a.editTier !== b.editTier) return a.editTier === 'AIGegenereerd' ? -1 : 1
            return a.readScore - b.readScore
          }).slice(0, 2).map(s => s.label)

        result = { sections: mergedSections, averageReadScore, overallReadTier, overallEditTier, weakestReadLabels, weakestEditLabels }
      }
      readingAnalysisRef.current = result
      return result
    })
  }, [])
  // Tracker mounted flag — wait one frame after LesTab mounts so phase cards are in DOM
  const [trackerMounted, setTrackerMounted] = useState(false)

  // Manual edit tracking — only counts explicit user keystrokes, not AI generation
  const [manualEditTexts, setManualEditTexts] = useState<Record<string, string | null>>({
    introductie: null, instructie: null, verwerking: null, afronding: null,
  })

  const handleManualInput = useCallback((phase: string, html: string) => {
    setManualEditTexts(prev => ({ ...prev, [phase]: html }))
  }, [])

  const mainLevel    = EDU_LEVELS.find(l => l.id === educatieNiveau)
  const subLevel     = mainLevel?.subLevels?.find((s: any) => s.id === educatieSpecifiekNiveau) as any
  const subSubLevel  = subLevel?.subSubLevels?.find((s: any) => s.id === educatieSpecifiekeRichting)
  const doelgroepStr = educatieNiveau === 'Anders' ? (customEducation || 'Anders')
    : [mainLevel?.label, subLevel?.label, subSubLevel?.label].filter(Boolean).join(' - ')

  const buildPayload = React.useCallback((extra: {[k: string]: unknown} = {}) => {
    const plainText = stripHtml(lesText)
    const lev = levenshtein(plainText, EXPERIMENT_TEXT)
    const { corrected, uncorrected, undetectable, rate } = countCorrectedErrors(plainText)
    const additionalMs = lesEditStartRef.current !== null ? Date.now() - lesEditStartRef.current : 0
    const finalLesEditSec = Math.round((lesEditMsRef.current + additionalMs) / 1000)
    const ra = readingAnalysisRef.current
    return JSON.stringify({
      participant_id:        participantIdRef.current,
      levenshtein_distance:  lev,
      error_correction_rate: rate,
      errors_corrected:      corrected.join(','),
      errors_uncorrected:    uncorrected.join(','),
      errors_undetectable:   undetectable.join(','),
      final_text:            plainText,
      submitted_at:          new Date().toISOString(),
      lesonderwerp:          onderwerp,
      doelgroep:             doelgroepStr,
      lesdoel_text:          lesdoel,
      lesduur_min:           lesduur ?? null,
      les_edit_time_sec:     finalLesEditSec,
      ai_prompt_count:       aiInteractions.length,
      ai_prompts:            aiInteractions.map(i => (i as AiInteraction).prompt).join(' | '),
      ai_interactions:       JSON.stringify(aiInteractions),
      manual_edit_count:     manualEditCountRef.current,
      simon_read_tier:       ra?.overallReadTier ?? 'geen data',
      simon_edit_tier:       ra?.overallEditTier ?? 'geen data',
      simon_read_score:      ra?.averageReadScore ?? 0,
      ...extra,
    })
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [lesText, onderwerp, lesdoel, lesduur, aiInteractions])

  const sendSnapshot = React.useCallback((step: string) => {
    return fetch('https://formspree.io/f/xojpoypd', {
      method:  'POST',
      headers: { 'Content-Type': 'application/json' },
      body:    buildPayload({ submission_type: 'intermediate', step }),
    }).catch(() => {})
  }, [buildPayload])

  const handleLesNext = React.useCallback(async () => {
    handleLesTabLeave()
    setLesNextLoading(true)
    await new Promise(r => setTimeout(r, 0))
    await sendSnapshot('les')
    setLesNextLoading(false)
    setActiveTab('voorvertoning')
  }, [handleLesTabLeave, sendSnapshot])

  useEffect(() => {
    const handleUnload = () => {
      if (appStep === 'library') return
      const blob = new Blob(
        [buildPayload({ submission_type: 'unload', step: activeTab })],
        { type: 'application/json' },
      )
      navigator.sendBeacon('https://formspree.io/f/xojpoypd', blob)
    }
    window.addEventListener('beforeunload', handleUnload)
    return () => window.removeEventListener('beforeunload', handleUnload)
  }, [buildPayload, appStep, activeTab])

  const wordCount      = onderwerp.trim().split(/\s+/).filter(Boolean).length
  const isDetailsValid = !!educatieNiveau && wordCount >= 3 && lesdoel.trim().length > 0

  const handleSaveDetails = () => {
    if (!isDetailsValid) return
    setTopTab('authoring')
    setAppStep('authoring')
  }

  // Lesdoel: 2s fake thinking time
  const handleGenerateLesdoel = () => {
    if (wordCount < 3) return
    setLesdoelLoading(true)
    setLesdoel('')
    setShowLesdoelInput(false)
    setTimeout(() => {
      setLesdoel(LESSON_LESDOEL)
      setShowLesdoelInput(true)
      setLesdoelLoading(false)
    }, 2000)
  }

  const handleDeelMetCollega = async () => {
    setSubmitting(true); setSubmitError(null)
    await new Promise(resolve => setTimeout(resolve, 0))
    const additionalMs = lesEditStartRef.current !== null ? Date.now() - lesEditStartRef.current : 0
    lesEditStartRef.current = null
    const finalLesEditSec = Math.round((lesEditMsRef.current + additionalMs) / 1000)
    const plainText = stripHtml(lesText)
    const lev = levenshtein(plainText, EXPERIMENT_TEXT)
    const { corrected, uncorrected, undetectable, rate } = countCorrectedErrors(plainText)

    // Compute per-phase edit ratios using the same logic as editTierForPhase
    const phaseEditRatios: Record<string, number> = {}
    const phases: OutlinePhase[] = ['introductie', 'instructie', 'verwerking', 'afronding']
    for (const phase of phases) {
      const original = ORIGINAL_PHASE_TEXT[phase] ?? ''
      const outlineKey = phase
      const currentText = manualEditTexts[outlineKey] !== null && manualEditTexts[outlineKey] !== undefined
        ? stripHtmlForEdit(manualEditTexts[outlineKey] as string)
        : (phaseBlocks[phase] ?? []).join('\n')
      const dist = simpleLevenshtein(
        currentText.replace(/\s+/g, ' ').trim(),
        original.replace(/\s+/g, ' ').trim()
      )
      phaseEditRatios[phase] = original.length > 0 ? Math.round((dist / original.length) * 1000) / 1000 : 0
    }
    const overallEditRatio = Math.round(
      phases.reduce((s, p) => s + phaseEditRatios[p], 0) / phases.length * 1000
    ) / 1000
    try {
      const res = await fetch('https://formspree.io/f/xojpoypd', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          participant_id: participantIdRef.current,
          levenshtein_distance: lev,
          error_correction_rate: rate,
          errors_corrected: corrected.join(','),
          errors_uncorrected: uncorrected.join(','),
          errors_undetectable: undetectable.join(','),
          final_text: plainText,
          submitted_at: new Date().toISOString(),
          lesonderwerp: onderwerp,
          doelgroep: doelgroepStr,
          lesdoel_text: lesdoel,
          lesduur_min:  lesduur ?? null,
          les_edit_time_sec:  finalLesEditSec,
          simon_read_tier: readingAnalysisRef.current?.overallReadTier ?? 'geen data',
          simon_edit_tier: readingAnalysisRef.current?.overallEditTier ?? 'geen data',
          simon_read_score: readingAnalysisRef.current?.averageReadScore ?? 0,
          // AI interaction tracking
          ai_prompt_count:    aiInteractions.length,
          ai_prompts:         aiInteractions.map(i => i.prompt).join(' | '),
          ai_interactions:    JSON.stringify(aiInteractions),
          // Edit ratio per phase (0 = unchanged, 1 = fully rewritten)
          edit_ratio_introductie: phaseEditRatios['introductie'],
          edit_ratio_instructie:  phaseEditRatios['instructie'],
          edit_ratio_verwerking:  phaseEditRatios['verwerking'],
          edit_ratio_afronding:   phaseEditRatios['afronding'],
          edit_ratio_overall:     overallEditRatio,
          manual_edit_count:  manualEditCountRef.current,
        }),
      })
      if (!res.ok) throw new Error('failed')
      setSubmitted(true)
      setShareModalOpen(false); setAppStep('post-library')
    } catch {
      setSubmitError('Er is iets misgegaan. Probeer het opnieuw.')
    } finally {
      setSubmitting(false)
    }
  }

  if (appStep === 'library') return <LibraryPage onStart={() => { setAppStep('details'); setSubmitted(false) }} />
  if (appStep === 'post-library') return <PostLibraryPage lesTitle={onderwerp || 'Mijn les'} />

  const activeLesdoel   = lesdoel || LESSON_LESDOEL
  const detailsComplete = isDetailsValid

  return (
    <div className="min-h-screen bg-[#FAFBFD]" style={{ fontFamily: 'Inter, system-ui, sans-serif' }}>
      <div className="flex h-screen overflow-hidden">

        {/* Sidebar — logo only */}
        <aside className="hidden md:flex flex-col w-16 bg-white border-r border-gray-100 pt-5 items-center shrink-0">
          <div className="w-10 h-10 rounded-full bg-gradient-to-r from-[#E13AA1] to-[#F63] flex items-center justify-center text-white font-bold text-sm">M</div>
        </aside>

        <main className="flex-1 overflow-hidden flex flex-col">

          {/* ── Top navigation: Lesdetails | Auteursomgeving ── */}
          <div className="bg-white border-b border-gray-200 px-4 flex items-end shrink-0">
            <button onClick={() => setTopTab('details')}
              className={`px-6 py-3 text-sm font-medium rounded-t-lg border-b-2 transition-all ${
                topTab === 'details' ? 'border-[#039B96] bg-white text-gray-900' : 'border-transparent text-gray-500 hover:text-gray-700 hover:bg-gray-50'
              }`}>
              Lesdetails
            </button>

            <div className="relative group">
              <button onClick={() => { if (detailsComplete) setTopTab('authoring') }}
                disabled={!detailsComplete}
                className={`px-6 py-3 text-sm font-medium rounded-t-lg border-b-2 transition-all disabled:cursor-not-allowed ${
                  topTab === 'authoring'
                    ? 'border-[#039B96] bg-white text-gray-900'
                    : detailsComplete
                      ? 'border-transparent text-gray-500 hover:text-gray-700 hover:bg-gray-50'
                      : 'border-transparent text-gray-400 opacity-50'
                }`}>
                Auteursomgeving
              </button>
              {!detailsComplete && (
                <div className="absolute left-0 top-full mt-1 px-3 py-1.5 bg-gray-900 text-white text-xs rounded-md whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity z-10 pointer-events-none">
                  Vul eerst de lesdetails in
                </div>
              )}
            </div>
          </div>

          {/* ── Content area ── */}
          <div className="flex-1 overflow-hidden relative">

            {topTab === 'details' && (
              <LesDetailsTab
                educatieNiveau={educatieNiveau} setEducatieNiveau={setEducatieNiveau}
                educatieSpecifiekNiveau={educatieSpecifiekNiveau} setEducatieSpecifiekNiveau={setEducatieSpecifiekNiveau}
                educatieSpecifiekeRichting={educatieSpecifiekeRichting} setEducatieSpecifiekeRichting={setEducatieSpecifiekeRichting}
                customEducation={customEducation} setCustomEducation={setCustomEducation}
                customSubLevel={customSubLevel} setCustomSubLevel={setCustomSubLevel}
                onderwerp={onderwerp} setOnderwerp={setOnderwerp}
                lesdoel={lesdoel} setLesdoel={setLesdoel}
                showLesdoelInput={showLesdoelInput} setShowLesdoelInput={setShowLesdoelInput}
                lesdoelLoading={lesdoelLoading} onGenerateLesdoel={handleGenerateLesdoel}
                kwalificatieEnabled={kwalificatieEnabled} setKwalificatieEnabled={setKwalificatieEnabled}
                educationStandards={educationStandards} setEducationStandards={setEducationStandards}
                taxonomieEnabled={taxonomieEnabled} setTaxonomieEnabled={setTaxonomieEnabled}
                selectedTaxonomie={selectedTaxonomie} setSelectedTaxonomie={setSelectedTaxonomie}
                selectedTaxNiveau={selectedTaxNiveau} setSelectedTaxNiveau={setSelectedTaxNiveau}
                doelgroepStr={doelgroepStr} isValid={isDetailsValid} onSave={handleSaveDetails}
              />
            )}

            {topTab === 'authoring' && (
              <div className="flex flex-col h-full overflow-hidden">
                <div className="flex-1 overflow-hidden relative">
                  {activeTab === 'lesplan' && (
                    <LesplanTab lesduur={lesduur} setLesduur={setLesduur}
                      verwerkingOpdracht={VERWERKING} lesdoel={activeLesdoel}
                      onNext={() => setActiveTab('lesoverzicht')} />
                  )}
                  {activeTab === 'lesoverzicht' && (
                    <LesoverzichtTab
                      lessonOutline={lessonOutline} setLessonOutline={setLessonOutline}
                      lesText={lesText} setLesText={setLesText} setPhaseBlocks={setPhaseBlocks}
                      lesdoel={activeLesdoel}
                      loaded={lesoverzichtLoaded} setLoaded={setLesoverzichtLoaded}
                      onPrev={() => setActiveTab('lesplan')}
                      onNext={() => setActiveTab('les')} />
                  )}
                  {activeTab === 'les' && (
                    <LesTab lesText={lesText} setLesText={setLesText}
                      phaseBlocks={phaseBlocks} setPhaseBlocks={setPhaseBlocks}
                      lessonOutline={lessonOutline} lesdoel={activeLesdoel} condition={condition}
                      loaded={lesLoaded} setLoaded={setLesLoaded}
                      onLesTabEnter={handleLesTabEnter} onLesTabLeave={handleLesTabLeave}
                      onAiInteraction={handleAiInteraction}
                      onManualEditCount={handleManualEditCount}
                      trackerMounted={trackerMounted} setTrackerMounted={setTrackerMounted}
                      readingAnalysis={readingAnalysis} onReadingAnalysis={stableSetAnalysis}
                      manualEditTexts={manualEditTexts} onManualInput={handleManualInput}
                      nextLoading={lesNextLoading}
                      onPrev={() => { handleLesTabLeave(); setActiveTab('lesoverzicht') }}
                      onNext={handleLesNext} />
                  )}
                  {activeTab === 'voorvertoning' && (
                    <VoorvertoningTab lesText={lesText} lesdoel={activeLesdoel} condition={condition}
                      onPrev={() => setActiveTab('les')}
                      onShare={() => { setShareTab('students'); setShareModalOpen(true) }} />
                  )}
                </div>
              </div>
            )}
          </div>
        </main>
      </div>

      {shareModalOpen && (
        <ShareModal tab={shareTab} setTab={setShareTab}
          onClose={() => setShareModalOpen(false)}
          onDeelMetCollega={handleDeelMetCollega}
          onLesOpSlot={() => {handleDeelMetCollega()}}
          submitting={submitting} submitted={submitted} error={submitError} lesText={lesText} />
      )}
    </div>
  )
}

