function stripHtml(html: string): string {
  return html
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/?(p|div|h[1-6]|li)[^>]*>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&nbsp;/g, ' ')
    .replace(/\n{3,}/g, '\n\n').trim()
}

// Same as stripHtml but used specifically for edit tier comparison
function stripHtmlForEdit(html: string): string {
  return html
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/?(p|div|h[1-6]|li)[^>]*>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&nbsp;/g, ' ')
    .replace(/\n{3,}/g, '\n\n').trim()
}

function stripMarks(html: string): string {
  return html.replace(/<mark[^>]*>([\s\S]*?)<\/mark>/gi, '$1')
}

function markdownToHtml(text: string): string {
  const lines = text.split('\n')
  const parts: string[] = []
  let i = 0
  while (i < lines.length) {
    const line = lines[i]
    if (/^###\s*/.test(line)) { parts.push(`<h3>${escHtml(line.replace(/^###\s*/, ''))}</h3>`); i++; continue }
    if (/^##\s*/.test(line))  { parts.push(`<h2>${escHtml(line.replace(/^##\s*/, ''))}</h2>`); i++; continue }
    if (/^#\s*/.test(line))   { parts.push(`<h1>${escHtml(line.replace(/^#\s*/, ''))}</h1>`); i++; continue }
    if (line.startsWith('- ') || line.startsWith('* ')) {
      const items: string[] = []
      while (i < lines.length && (lines[i].startsWith('- ') || lines[i].startsWith('* '))) {
        items.push(`<li>${inlineFormat(lines[i].slice(2))}</li>`)
        i++
      }
      parts.push(`<ul>${items.join('')}</ul>`)
      continue
    }
    if (/^\d+\. /.test(line)) {
      const items: string[] = []
      while (i < lines.length && /^\d+\. /.test(lines[i])) {
        items.push(`<li>${inlineFormat(lines[i].replace(/^\d+\. /, ''))}</li>`)
        i++
      }
      parts.push(`<ol>${items.join('')}</ol>`)
      continue
    }
    if (!line.trim()) { parts.push('<p><br></p>'); i++; continue }
    parts.push(`<p>${inlineFormat(line)}</p>`)
    i++
  }
  return parts.join('')
}

function escHtml(s: string): string {
  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
}

function htmlToPlain(html: string): string {
  return html
    .replace(/<h1[^>]*>([\s\S]*?)<\/h1>/gi, (_,t) => `# ${t.replace(/<[^>]+>/g,'')}\n`)
    .replace(/<h2[^>]*>([\s\S]*?)<\/h2>/gi, (_,t) => `## ${t.replace(/<[^>]+>/g,'')}\n`)
    .replace(/<h3[^>]*>([\s\S]*?)<\/h3>/gi, (_,t) => `### ${t.replace(/<[^>]+>/g,'')}\n`)
    .replace(/<h4[^>]*>([\s\S]*?)<\/h4>/gi, (_,t) => `#### ${t.replace(/<[^>]+>/g,'')}\n`)
    .replace(/<li[^>]*>([\s\S]*?)<\/li>/gi, (_,t) => `- ${t.replace(/<[^>]+>/g,'')}\n`)
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/?(p|div|ul|ol)[^>]*>/gi, '\n')
    .replace(/<strong[^>]*>([\s\S]*?)<\/strong>/gi, (_,t) => `**${t}**`)
    .replace(/<em[^>]*>([\s\S]*?)<\/em>/gi, (_,t) => `*${t}*`)
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&nbsp;/g, ' ')
    .replace(/\n{3,}/g, '\n\n').trim()
}

